// Get the PDF text content and record info
const pdfText = $input.item.json.text || '';
const recordId = $input.item.json.id;
const auctionName = $input.item.json.fields["Auction Name"] || "Unknown Auction";
const county = $input.item.json.fields["County"] ? $input.item.json.fields["County"][0] : "Unknown County";

// Split the text into lines for processing
const lines = pdfText.split('\n');

// Initialize array to store foreclosure records
const foreclosures = [];

// Define the column headers we're looking for
const headers = [
  "PARCEL", "TOWN", "SBL#", "INDEX #", "LOCATION", "OLDEST YEAR OF TAX", 
  "ACCEPT", "SUM OF DELINQUENT TAX", "SURPLUS FUNDS"
];

// Process line by line
let inDataSection = false;
let currentRow = {};

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();

  // Check if this line contains the column headers
  if (line.includes("PARCEL") && line.includes("TOWN") && line.includes("SBL#")) {
    inDataSection = true;
    continue;
  }

  // Skip empty lines or header rows
  if (!inDataSection || line === '' || line.includes("Page |")) {
    continue;
  }

  // Check if this looks like a parcel entry (typically starts with a number followed by municipality)
  const parcelMatch = line.match(/^\s*(\d+)\s+([A-Z]+)/);

  if (parcelMatch) {
    // If we already have a row in progress, save it
    if (Object.keys(currentRow).length > 0) {
      foreclosures.push({...currentRow});
    }

    // Start a new row
    currentRow = {
      parcelNumber: parcelMatch[1].trim(),
      town: parcelMatch[2].trim()
    };

    // Extract SBL# - usually follows after the town
    const sblMatch = line.match(/([\d\.-]+)[\s\n]+([\d\-]+)[\s\n]/);
    if (sblMatch) {
      currentRow.sbl = sblMatch[1].trim();
    }

    // Extract Index # if present
    const indexMatch = line.match(/([\d\-]+)[\s\n]+([\w\s\/\.]+)\s+([\d]{4})/);
    if (indexMatch) {
      currentRow.indexNumber = indexMatch[1].trim();
      // Location is typically right after the index number
      currentRow.location = indexMatch[2].trim();
    }

    // Try to find the sale price (Accept)
    const salePriceMatch = line.match(/\$(\s*[\d,]+\.\d+)\s+\$(\s*[\d,]+\.\d+)\s+\$(\s*[\d,]+\.\d+)/);
    if (salePriceMatch) {
      currentRow.salePrice = salePriceMatch[1].replace(/[^\d\.]/g, '');
      currentRow.tax = salePriceMatch[2].replace(/[^\d\.]/g, '');
      currentRow.surplus = salePriceMatch[3].replace(/[^\d\.]/g, '');
    }

    // Add auction reference data
    currentRow.auctionId = recordId;
    currentRow.auctionName = auctionName;
    currentRow.county = county;
  } 
  // Check if this is a continuation of the previous row (for multi-line entries)
  else if (Object.keys(currentRow).length > 0) {
    // If we don't have a location yet, this might be it
    if (!currentRow.location) {
      currentRow.location = line.trim();
    }

    // Check for monetary values on this line
    const moneyMatch = line.match(/\$(\s*[\d,]+\.\d+)\s+\$(\s*[\d,]+\.\d+)\s+\$(\s*[\d,]+\.\d+)/);
    if (moneyMatch && !currentRow.salePrice) {
      currentRow.salePrice = moneyMatch[1].replace(/[^\d\.]/g, '');
      currentRow.tax = moneyMatch[2].replace(/[^\d\.]/g, '');
      currentRow.surplus = moneyMatch[3].replace(/[^\d\.]/g, '');
    }
  }
}

// Don't forget the last row
if (Object.keys(currentRow).length > 0) {
  foreclosures.push({...currentRow});
}

// Map to the field names the user specified
const mappedForeclosures = foreclosures.map(f => {
  return {
    Number: f.parcelNumber,
    SBL: f.sbl,
    "Deed Book": f.indexNumber, // Using Index # as Deed Book
    Location: f.location,
    "Sale Price": parseFloat(f.salePrice),
    Tax: parseFloat(f.tax),
    Surplus: parseFloat(f.surplus),
    Auction: [recordId],  // Link to the auction record
    Town: f.town,
    County: f.county
  };
});

// Return all foreclosures found with relationship to auction
return {
  json: {
    auctionId: recordId,
    auctionName: auctionName,
    county: county,
    foreclosuresCount: mappedForeclosures.length,
    foreclosures: mappedForeclosures
  }
};
